  function stClass(s){s=(s||'open').toLowerCase();return ST[s]?s:'open';}

  function sendMsg(txt){
    try{var w=window.parent||window;var ta=w.document.getElementById('send_textarea')||w.document.querySelector('textarea.chat-input,#textareaAutosize,textarea');
      if(ta){var dd=Object.getOwnPropertyDescriptor(w.HTMLTextAreaElement.prototype,'value');if(dd&&dd.set)dd.set.call(ta,txt);else ta.value=txt;ta.dispatchEvent(new Event('input',{bubbles:true}));
