    if(has(m.poster))meta+='<div class="drow"><b>'+L('Issued by','ออกโดย')+'</b><span>'+esc(m.poster)+'</span></div>';
    if(has(D.board))meta+='<div class="drow"><b>'+L('Board','กระดาน')+'</b><span>'+esc(D.board)+'</span></div>';
    meta+='<div class="drow"><b>'+L('Status','สถานะ')+'</b><span>'+L(ST[st][0],ST[st][1])+'</span></div>';
    root.innerHTML='<div class="slip"><div class="seal">'+L('SEAL','ผนึก')+'</div>'+
