      '<div class="stop">'+(has(m.rank)?'<div class="rank">'+esc(m.rank)+'</div>':'')+
      '<div class="nhd"><div class="stitle">'+esc(m.title)+'</div>'+(has(m.type)?'<div class="stype">'+esc(m.type)+'</div>':'')+'</div></div>'+
      (has(m.desc)?'<div class="sdesc">'+esc(m.desc)+'</div>':'')+
      '<div class="smeta">'+meta+'</div></div>';
