        '<div class="ntop">'+(has(m.rank)?'<div class="rank">'+esc(m.rank)+'</div>':'')+
        '<div class="nhd"><div class="ntitle">'+esc(m.title)+'</div>'+(has(m.type)?'<div class="ntype">'+esc(m.type)+'</div>':'')+'</div></div>'+
